UPDATE words SET example_en_2 = 'The military junta announced it would hold elections in two years.', example_ko_2 = '군사 정권은 2년 내에 선거를 열겠다고 발표했어요.', example_en_3 = 'The junta banned political parties and arrested opposition leaders.', example_ko_3 = '군사 정권이 정당을 금지하고 야당 지도자들을 체포했어요.', example_en_4 = 'International sanctions were imposed on the junta after the coup.', example_ko_4 = '쿠데타 이후 군사 정권에 국제 제재가 부과됐어요.', example_en_5 = 'The junta''s grip on power weakened as protests grew.', example_ko_5 = '시위가 커지면서 군사 정권의 권력 장악이 약해졌어요.' WHERE id = 'w_news_C1_19';

