UPDATE words SET example_en_2 = 'Determining culpability for the disaster took years of investigation.', example_ko_2 = '재난에 대한 유책성 결정에 수년간의 조사가 걸렸어요.', example_en_3 = 'The inquiry examined the culpability of both the company and the regulator.', example_ko_3 = '조사는 회사와 규제 기관 모두의 유책성을 검토했어요.', example_en_4 = 'Shared culpability made it difficult to assign individual blame.', example_ko_4 = '공동 유책성은 개인의 잘못을 지정하는 것을 어렵게 만들었어요.', example_en_5 = 'The verdict established the culpability of the entire leadership.', example_ko_5 = '판결은 전체 지도부의 유책성을 확립했어요.' WHERE id = 'w_news_C1_22';

