UPDATE words SET example_en_2 = 'The senator''s demagogue tactics polarized the electorate.', example_ko_2 = '상원 의원의 선동가 전술이 유권자들을 양극화했어요.', example_en_3 = 'A skilled demagogue can exploit economic anxiety to gain power.', example_ko_3 = '능숙한 선동가는 경제적 불안을 이용해 권력을 얻을 수 있어요.', example_en_4 = 'History shows that demagogues often rise during periods of crisis.', example_ko_4 = '역사는 선동가들이 종종 위기 기간에 부상함을 보여줘요.', example_en_5 = 'Calling someone a demagogue does not itself disprove their arguments.', example_ko_5 = '누군가를 선동가라고 부르는 것이 그들의 주장을 반증하지는 않아요.' WHERE id = 'w_news_C1_29';

